    pull.filterNot(/^[^e]+$/i), //no E
    pull.take(37),
    pull.collect(function (err, array) {
      t.equal(array.length, 37)
      array.forEach(function (d) {
        t.notEqual(d.indexOf('e'), -1)
      })
      t.end()
    })
  )
})


